def _tokenize(expr):
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        if c.isdigit() or c == '.':
            j = i
            has_dot = False
            has_digit = False
            while j < n and (expr[j].isdigit() or (expr[j] == '.' and not has_dot)):
                if expr[j] == '.':
                    has_dot = True
                else:
                    has_digit = True
                j += 1
            if not has_digit:
                raise ValueError(f"Invalid number at position {i}")
            tokens.append(('NUMBER', expr[i:j]))
            i = j
            continue
        if c == '*':
            if i + 1 < n and expr[i + 1] == '*':
                tokens.append(('POW', '**'))
                i += 2
            else:
                tokens.append(('MUL', '*'))
                i += 1
            continue
        if c == '/':
            tokens.append(('DIV', '/'))
            i += 1
            continue
        if c == '+':
            tokens.append(('PLUS', '+'))
            i += 1
            continue
        if c == '-':
            tokens.append(('MINUS', '-'))
            i += 1
            continue
        if c == '(':
            tokens.append(('LPAREN', '('))
            i += 1
            continue
        if c == ')':
            tokens.append(('RPAREN', ')'))
            i += 1
            continue
        raise ValueError(f"Illegal character {c!r} at position {i}")
    tokens.append(('END', ''))
    return tokens


class _Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def peek(self):
        return self.tokens[self.pos]

    def advance(self):
        tok = self.tokens[self.pos]
        self.pos += 1
        return tok

    def expect(self, type_):
        tok = self.peek()
        if tok[0] != type_:
            raise ValueError(f"Expected {type_} but found {tok[0]!r}")
        return self.advance()

    def parse(self):
        value = self.parse_expr()
        if self.peek()[0] != 'END':
            raise ValueError(f"Unexpected token {self.peek()[1]!r}")
        return value

    def parse_expr(self):
        value = self.parse_term()
        while self.peek()[0] in ('PLUS', 'MINUS'):
            op = self.advance()[0]
            right = self.parse_term()
            value = value + right if op == 'PLUS' else value - right
        return value

    def parse_term(self):
        value = self.parse_unary()
        while self.peek()[0] in ('MUL', 'DIV'):
            op = self.advance()[0]
            right = self.parse_unary()
            if op == 'MUL':
                value = value * right
            else:
                if right == 0:
                    raise ZeroDivisionError("division by zero")
                value = value / right
        return value

    def parse_unary(self):
        if self.peek()[0] == 'MINUS':
            self.advance()
            return -self.parse_unary()
        return self.parse_power()

    def parse_power(self):
        base = self.parse_primary()
        if self.peek()[0] == 'POW':
            self.advance()
            exponent = self.parse_unary()
            return base ** exponent
        return base

    def parse_primary(self):
        tok = self.peek()
        if tok[0] == 'NUMBER':
            self.advance()
            return float(tok[1])
        if tok[0] == 'LPAREN':
            self.advance()
            value = self.parse_expr()
            self.expect('RPAREN')
            return value
        raise ValueError(f"Unexpected token {tok[1]!r}")


def evaluate(expr: str) -> float:
    tokens = _tokenize(expr)
    parser = _Parser(tokens)
    return float(parser.parse())
